                        # Clear graph from unnecesary edges
                        remove=set()
                        for edge in edges:
                            (i,j)=edge
                            if i in sets[1] and j in sets[1] :
                                remove.add(edge)
                        for edge in remove:
                            edges.remove(edge)
                        
                        
                        
                        match interdiction_type:
                            case "edge mzn":
                                T=determine_T(edges,sets)
                                T=set(T)-set(new_infected)
